import React from 'react'
import { Link } from 'react-router-dom';
import Room from './Room';



export default function MyRooms(props) {
    return (
        <div>
            {props.rooms.map((i) => {
                console.log(i)
                return (<Room name={i.name} />)
            })}}

            <Link to={"/"}><button>Back</button> </Link>
        </div>
    )
}
